def fib(n: int, memo: dict = None) -> int:
    # Initialize the dictionary on the first call
    if memo is None:
        memo = {}

    # Base cases
    if n == 0:
        return 0
    if n == 1:
        return 1

    # Check if the value is already in the memo
    if n in memo:
        return memo[n]

    # Recursive step: calculate, store in memo, and return
    memo[n] = fib(n - 1, memo) + fib(n - 2, memo)
    return memo[n]

